class InvalidRGBColorError(Exception):
    pass

def validate_rgb_color(color_code):
    if len(color_code) != 6:
        raise InvalidRGBColorError("Invalid RGB color code. Must be 6 hexadecimal digits.")

    try:
        int(color_code, 16)
    except ValueError:
        raise InvalidRGBColorError("Invalid RGB color code. Must be 6 hexadecimal digits.")

    return color_code.upper()

if __name__ == "__main__":
    color_code = input().strip()
    try:
        result = validate_rgb_color(color_code)
        print(result)
    except InvalidRGBColorError as e:
        print(str(e))
